#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <sys/types.h>
#include <fcntl.h>
#include <errno.h>

#define MAX_PATH 256
#define BUFFER_SIZE 1024

// Structure to hold file metadata (simulating inode info)
typedef struct {
 ino_t inode; // Inode number
 nlink_t nlink; // Number of hard links
 uid_t owner; // Owner user ID
 gid_t group; // Owner group ID
 mode_t mode; // File permissions
 off_t size; // File size
} FileMetadata;

// Function to get and display file metadata
void get_file_metadata(const char *filepath, FileMetadata *meta) {
 struct stat file_stat;

 if (stat(filepath, &file_stat) == -1) {
 perror("stat failed");
 return;
 }

 meta->inode = file_stat.st_ino;
 meta->nlink = file_stat.st_nlink;
 meta->owner = file_stat.st_uid;
 meta->group = file_stat.st_gid;
 meta->mode = file_stat.st_mode;
 meta->size = file_stat.st_size;
}

// Convert mode to permission string (rwxr-xr-x format)
void mode_to_string(mode_t mode, char *perm_str) {
 // Owner permissions
 perm_str[0] = (mode & S_IRUSR) ? 'r' : '-';
 perm_str[1] = (mode & S_IWUSR) ? 'w' : '-';
 perm_str[2] = (mode & S_IXUSR) ? 'x' : '-';

 // Group permissions
 perm_str[3] = (mode & S_IRGRP) ? 'r' : '-';
 perm_str[4] = (mode & S_IWGRP) ? 'w' : '-';
 perm_str[5] = (mode & S_IXGRP) ? 'x' : '-';

 // Other permissions
 perm_str[6] = (mode & S_IROTH) ? 'r' : '-';
 perm_str[7] = (mode & S_IWOTH) ? 'w' : '-';
 perm_str[8] = (mode & S_IXOTH) ? 'x' : '-';

 perm_str[9] = '\0';
}

// Display file metadata
void display_metadata(const char *filename, FileMetadata *meta) {
 char perms[10];
 mode_to_string(meta->mode, perms);

 printf("\n=== File: %s ===\n", filename);
 printf("Inode: %lu\n", (unsigned long)meta->inode);
 printf("Hard links: %hu\n", meta->nlink);
 printf("Owner UID: %u\n", meta->owner);
 printf("Group GID: %u\n", meta->group);
 printf("Permissions: %s\n", perms);
 printf("Size: %ld bytes\n", (long)meta->size);
}

// Check if user has read permission
int check_read_permission(const char *filepath) {
 return (access(filepath, R_OK) == 0);
}

// Check if user has write permission
int check_write_permission(const char *filepath) {
 return (access(filepath, W_OK) == 0);
}

// Check if user has execute permission
int check_execute_permission(const char *filepath) {
 return (access(filepath, X_OK) == 0);
}

// Demonstrate file sharing with hard links
void demonstrate_hard_links(const char *dir_path) {
 char original[MAX_PATH], hardlink[MAX_PATH];
 FileMetadata meta_orig, meta_hlink;

 snprintf(original, MAX_PATH, "%s/original.txt", dir_path);
 snprintf(hardlink, MAX_PATH, "%s/hardlink.txt", dir_path);

 // Create original file
 int fd = open(original, O_WRONLY | O_CREAT | O_TRUNC, 0644);
 if (fd == -1) {
 perror("Failed to create original file");
 return;
 }
 write(fd, "Original file content", 21);
 close(fd);

 // Create hard link using link() system call
 if (link(original, hardlink) == -1) {
 perror("Failed to create hard link");
 return;
 }

 // Get metadata for both files
 get_file_metadata(original, &meta_orig);
 get_file_metadata(hardlink, &meta_hlink);

 printf("\n=== Hard Link Demonstration ===");
 display_metadata("original.txt", &meta_orig);
 display_metadata("hardlink.txt", &meta_hlink);

 printf("\nSame inode? %s\n", 
 (meta_orig.inode == meta_hlink.inode) ? "YES" : "NO");
 printf("Combined hard link count: %hu\n", meta_orig.nlink);

 // Delete original and show hard link still works
 unlink(original);

 if (access(hardlink, F_OK) == 0) {
 printf("After unlinking original, hardlink still exists: YES\n");
 }
}

// Demonstrate symbolic (soft) links
void demonstrate_soft_links(const char *dir_path) {
 char target[MAX_PATH], symlink[MAX_PATH];

 snprintf(target, MAX_PATH, "%s/target.txt", dir_path);
 snprintf(symlink, MAX_PATH, "%s/symlink.txt", dir_path);

 // Create target file
 FILE *fp = fopen(target, "w");
 if (!fp) {
 perror("Failed to create target file");
 return;
 }
 fprintf(fp, "Target file content");
 fclose(fp);

 // Create symbolic link using symlink()
 if (symlink(target, symlink) == -1) {
 perror("Failed to create symbolic link");
 return;
 }

 printf("\n=== Symbolic Link Demonstration ===");

 struct stat st;
 if (lstat(symlink, &st) == 0) {
 printf("symlink.txt is a symbolic link: %s\n", 
 S_ISLNK(st.st_mode) ? "YES" : "NO");
 }

 // Read the symbolic link target
 char link_target[MAX_PATH];
 ssize_t len = readlink(symlink, link_target, MAX_PATH - 1);
 if (len != -1) {
 link_target[len] = '\0';
 printf("Symbolic link points to: %s\n", link_target);
 }

 // Delete target and show symlink becomes dangling
 unlink(target);

 if (access(symlink, F_OK) == -1) {
 printf("After deleting target, symlink is now dangling (broken)\n");
 }
}

// Simulate basic ACL check
typedef struct {
 char user[32];
 int read:1;
 int write:1;
 int execute:1;
} ACLEntry;

typedef struct {
 char filename[MAX_PATH];
 ACLEntry entries[10];
 int entry_count;
} FileACL;

int check_acl_access(FileACL *acl, const char *user, const char *permission) {
 for (int i = 0; i < acl->entry_count; i++) {
 if (strcmp(acl->entries[i].user, user) == 0) {
 if (strcmp(permission, "read") == 0) return acl->entries[i].read;
 if (strcmp(permission, "write") == 0) return acl->entries[i].write;
 if (strcmp(permission, "execute") == 0) return acl->entries[i].execute;
 }
 }
 return 0; // User not in ACL = no access
}

void demonstrate_acl() {
 printf("\n=== ACL (Access Control List) Demonstration ===\n");

 FileACL acl;
 strcpy(acl.filename, "project.txt");
 acl.entry_count = 3;

 // Set ACL entries
 strcpy(acl.entries[0].user, "alice"); acl.entries[0].read = 1; acl.entries[0].write = 1; acl.entries[0].execute = 0;
 strcpy(acl.entries[1].user, "bob"); acl.entries[1].read = 1; acl.entries[1].write = 0; acl.entries[1].execute = 0;
 strcpy(acl.entries[2].user, "charlie"); acl.entries[2].read = 0; acl.entries[2].write = 0; acl.entries[2].execute = 1;

 // Test access
 printf("Alice can read: %s\n", check_acl_access(&acl, "alice", "read") ? "YES" : "NO");
 printf("Alice can write: %s\n", check_acl_access(&acl, "alice", "write") ? "YES" : "NO");
 printf("Bob can write: %s\n", check_acl_access(&acl, "bob", "write") ? "YES" : "NO");
 printf("Charlie can execute: %s\n", check_acl_access(&acl, "charlie", "execute") ? "YES" : "NO");
}

