import java.io.*;
import java.nio.file.*;
import java.nio.file.attribute.*;
import java.util.*;
import java.nio.charset.StandardCharsets;

public class FileSharingDemo {

 private static final Path DEMO_DIR = Paths.get("/tmp/java_file_sharing_demo");

 public static void main(String[] args) {
 try {
 // Create demo directory
 Files.createDirectories(DEMO_DIR);

 // Demonstrate basic file attributes
 demonstrateBasicAttributes();

 // Demonstrate file permissions (POSIX)
 demonstratePermissions();

 // Demonstrate hard and soft links
 demonstrateLinks();

 // Demonstrate ACL-like access control
 demonstrateACL();

 System.out.println("\n=== All Demonstrations Complete ===");

 } catch (IOException e) {
 System.err.println("Error: " + e.getMessage());
 e.printStackTrace();
 }
 }

 /**
 * Demonstrate reading basic file attributes
 */
 private static void demonstrateBasicAttributes() throws IOException {
 System.out.println("=== Basic File Attributes ===");

 Path testFile = DEMO_DIR.resolve("testfile.txt");
 String content = "This is a test file for demonstrating attributes.";
 Files.write(testFile, content.getBytes(StandardCharsets.UTF_8));

 // Read basic file attributes
 BasicFileAttributes attrs = Files.readAttributes(testFile, BasicFileAttributes.class);

 System.out.println("File: " + testFile.getFileName());
 System.out.println(" Size: " + attrs.size() + " bytes");
 System.out.println(" Creation Time: " + attrs.creationTime());
 System.out.println(" Last Modified: " + attrs.lastModifiedTime());
 System.out.println(" Is Regular File: " + attrs.isRegularFile());
 System.out.println(" Is Directory: " + attrs.isDirectory());
 System.out.println(" Is Symbolic Link: " + attrs.isSymbolicLink());
 }

 /**
 * Demonstrate POSIX file permissions (Unix/Linux)
 */
 private static void demonstratePermissions() throws IOException {
 System.out.println("\n=== POSIX File Permissions ===");

 Path permFile = DEMO_DIR.resolve("permissions_test.txt");
 Files.createFile(permFile);

 // Get POSIX file attributes (owner, group, permissions)
 PosixFileAttributes posixAttrs = Files.readAttributes(permFile, PosixFileAttributes.class);

 System.out.println("File: " + permFile.getFileName());
 System.out.println(" Owner: " + posixAttrs.owner().getName());
 System.out.println(" Group: " + posixAttrs.group().getName());
 System.out.println(" Permissions: " + posixAttrs.permissions());

 // Set new permissions using PosixFilePermission
 Set<PosixFilePermission> perms = new HashSet<>();
 perms.add(PosixFilePermission.OWNER_READ);
 perms.add(PosixFilePermission.OWNER_WRITE);
 perms.add(PosixFilePermission.GROUP_READ);
 perms.add(PosixFilePermission.OTHERS_READ);

 Files.setPosixFilePermissions(permFile, perms);

 // Read updated permissions
 posixAttrs = Files.readAttributes(permFile, PosixFileAttributes.class);
 System.out.println(" Updated Permissions: " + posixAttrs.permissions());

 // Display as rwxr-xr-- format
 System.out.println(" As string: " + permissionsToString(perms));
 }

 /**
 * Convert permissions to rwxr-xr-- format
 */
 private static String permissionsToString(Set<PosixFilePermission> perms) {
 StringBuilder sb = new StringBuilder();

 // Owner permissions
 sb.append(perms.contains(PosixFilePermission.OWNER_READ) ? "r" : "-");
 sb.append(perms.contains(PosixFilePermission.OWNER_WRITE) ? "w" : "-");
 sb.append(perms.contains(PosixFilePermission.OWNER_EXECUTE) ? "x" : "-");

 // Group permissions
 sb.append(perms.contains(PosixFilePermission.GROUP_READ) ? "r" : "-");
 sb.append(perms.contains(PosixFilePermission.GROUP_WRITE) ? "w" : "-");
 sb.append(perms.contains(PosixFilePermission.GROUP_EXECUTE) ? "x" : "-");

 // Others permissions
 sb.append(perms.contains(PosixFilePermission.OTHERS_READ) ? "r" : "-");
 sb.append(perms.contains(PosixFilePermission.OTHERS_WRITE) ? "w" : "-");
 sb.append(perms.contains(PosixFilePermission.OTHERS_EXECUTE) ? "x" : "-");

 return sb.toString();
 }

 /**
 * Demonstrate hard links and symbolic links
 */
 private static void demonstrateLinks() throws IOException {
 System.out.println("\n=== Hard Links and Symbolic Links ===");

 // Create original file
 Path original = DEMO_DIR.resolve("original.txt");
 Files.write(original, "Original content".getBytes(StandardCharsets.UTF_8));

 // Get original file's inode (via FileKey)
 BasicFileAttributes origAttrs = Files.readAttributes(original, BasicFileAttributes.class);
 FileStore store = Files.getFileStore(original);
 Object origKey = original.getFileSystem().provider().getFileAttributeView(
 original, BasicFileAttributeView.class).readAttributes().fileKey();

 // Create hard link
 Path hardLink = DEMO_DIR.resolve("hardlink.txt");
 Files.createLink(hardLink, original);

 BasicFileAttributes hlAttrs = Files.readAttributes(hardLink, BasicFileAttributes.class);

 System.out.println("Original file:");
 System.out.println(" Path: " + original);
 System.out.println(" Hard link count: " + origAttrs.size()); // size check as proxy
 System.out.println(" Content: " + new String(Files.readAllBytes(original)));

 System.out.println("\nHard Link:");
 System.out.println(" Path: " + hardLink);
 System.out.println(" Is same file: " + Files.isSameFile(original, hardLink));
 System.out.println(" Content: " + new String(Files.readAllBytes(hardLink)));

 // Delete original and show hard link survives
 Files.delete(original);
 System.out.println("\nAfter deleting original:");
 System.out.println(" Hard link still exists: " + Files.exists(hardLink));
 System.out.println(" Hard link content: " + new String(Files.readAllBytes(hardLink)));

 // Recreate original for symlink demo
 Files.write(original, "Target content".getBytes(StandardCharsets.UTF_8));

 // Create symbolic link
 Path symLink = DEMO_DIR.resolve("symlink.txt");
 Files.createSymbolicLink(symLink, original);

 System.out.println("\nSymbolic Link:");
 System.out.println(" Path: " + symLink);
 System.out.println(" Is symbolic link: " + Files.isSymbolicLink(symLink));
 System.out.println(" Target: " + Files.readSymbolicLink(symLink));

 // Delete target and show symlink becomes dangling
 Files.delete(original);
 System.out.println("\nAfter deleting target:");
 System.out.println(" Symbolic link exists: " + Files.exists(symLink));
 System.out.println(" Is symbolic link (still): " + Files.isSymbolicLink(symLink));
 }

 /**
 * ACL-like access control demonstration
 */
 private static void demonstrateACL() {
 System.out.println("\n=== ACL (Access Control List) Demonstration ===");

 // Simple ACL implementation
 class ACLEntry {
 String user;
 boolean read, write, execute;

 ACLEntry(String user, boolean read, boolean write, boolean execute) {
 this.user = user;
 this.read = read;
 this.write = write;
 this.execute = execute;
 }
 }

 class FileACL {
 String filename;
 List<ACLEntry> entries = new ArrayList<>();

 FileACL(String filename) {
 this.filename = filename;
 }

 void addEntry(String user, boolean read, boolean write, boolean execute) {
 entries.add(new ACLEntry(user, read, write, execute));
 }

 boolean checkAccess(String user, String permission) {
 for (ACLEntry entry : entries) {
 if (entry.user.equals(user)) {
 switch (permission.toLowerCase()) {
 case "read": return entry.read;
 case "write": return entry.write;
 case "execute": return entry.execute;
 }
 }
 }
 return false; // User not in ACL = no access
 }

 void printACL() {
 System.out.println("ACL for: " + filename);
 for (ACLEntry entry : entries) {
 System.out.printf(" %s: r=%s w=%s x=%s%n", 
 entry.user, 
 entry.read ? "+" : "-",
 entry.write ? "+" : "-",
 entry.execute ? "+" : "-");
 }
 }
 }

 // Create ACL for a shared project file
 FileACL projectACL = new FileACL("project_data.txt");
 projectACL.addEntry("professor", true, true, true);
 projectACL.addEntry("student_lead", true, true, false);
 projectACL.addEntry("student_worker", true, false, false);
 projectACL.addEntry("guest", false, false, false);

 projectACL.printACL();

 // Test access
 String[] testUsers = {"professor", "student_lead", "student_worker", "guest", "unknown"};
 String[] testPerms = {"read", "write", "execute"};

 System.out.println("\nAccess Tests:");
 for (String user : testUsers) {
 for (String perm : testPerms) {
 boolean granted = projectACL.checkAccess(user, perm);
 if (granted) {
 System.out.printf(" %s can %s: ALLOWED%n", user, perm);
 }
 }
 }
 }
}
